mapper.select:
SELECT id, name, state, partner_id, origin, scheduled_date, date_done, location_id, location_dest_id, company_id
FROM stock_picking


        AND (
            name ILIKE CONCAT('%', #{query.keyword}, '%')
            OR origin ILIKE CONCAT('%', #{query.keyword}, '%')
        )


        AND partner_id = #{query.partnerId}


        AND location_id = #{query.locationId}


        AND location_dest_id = #{query.locationDestId}


        AND state = #{query.state}


        AND DATE(scheduled_date) = #{query.scheduledDate}


ORDER BY id DESC
